const Keys={ESCAPE:"Escape",ESC:"Esc"},isEscEvent=e=>e.key===Keys.ESCAPE||e.key===Keys.ESC,popup=document.querySelector(".popup"),popupCloseButton=popup.querySelector(".popup__close"),openPopup=()=>{popup.classList.add("popup--open"),document.body.classList.add("no-scroll"),document.addEventListener("keydown",onPopupEscKeydown)},closePopup=()=>{popup.classList.remove("popup--open"),document.body.classList.remove("no-scroll"),document.removeEventListener("keydown",onPopupEscKeydown)},onPopupEscKeydown=e=>{isEscEvent(e)&&(e.preventDefault(),closePopup())};popupCloseButton.addEventListener("click",closePopup),popup.classList.add("popup--open"),document.body.classList.add("no-scroll"),document.addEventListener("keydown",onPopupEscKeydown);const numberField=document.querySelector(".number-field"),numberControl=numberField.querySelector(".number-field__control");numberField.querySelector(".number-field__button--minus").addEventListener("click",(()=>{numberControl.stepDown()})),numberField.querySelector(".number-field__button--plus").addEventListener("click",(()=>{numberControl.stepUp()}));